@page "/privacy"
@attribute [ExcludeFromInteractiveRouting]
@using Microsoft.AspNetCore.Http

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

@if (HasConsented)
{
    <div class="alert alert-success">
        ✔ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning">
        You have not yet accepted our cookie policy.
    </div>
}

<h2>How We Use Cookies</h2>
<p>
    This site uses cookies to improve your experience. We use cookies to remember
    your preferences, analyze site traffic, and personalize content.
</p>

<h2>Your Rights</h2>
<p>
    You may withdraw your consent at any time by clearing your browser cookies.
    For more information about your rights, please contact us.
</p>

@code {
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private bool HasConsented =>
        HttpContext?.Request.Cookies.ContainsKey("consent") == true;
}

